class AccountAlreadyClosedError(Exception):
    pass


class NonZeroBalanceError(Exception):
    """Raised when attempting to close an account that still has a balance
    without sweeping funds to another account first."""


class Account:
    def __init__(self, account_id: str, balance: Decimal = Decimal("0.00")):
        self.account_id = account_id
        self._balance = balance
        self.is_closed = False

    @property
    def balance(self) -> Decimal:
        return self._balance

    def deposit(self, amount: Decimal) -> None:
        if amount <= Decimal("0"):
            raise ValueError("Deposit amount must be positive.")
        self._balance += amount

    def withdraw(self, amount: Decimal) -> None:
        if amount <= Decimal("0"):
            raise ValueError("Withdrawal amount must be positive.")
        if amount > self._balance:
            raise InsufficientFundsError("Insufficient funds.")
        self._balance -= amount


class AccountService:
    """Service layer that enforces account-closure business rules."""

    def __init__(self):
        self._accounts: dict[str, Account] = {}

    def add_account(self, account: Account) -> None:
        self._accounts[account.account_id] = account

    def get_account(self, account_id: str) -> Account:
        try:
            return self._accounts[account_id]
        except KeyError:
            raise AccountNotFoundError(f"Account '{account_id}' not found.")

    def close_account(
        self,
        account_id: str,
        sweep_to_account_id: str | None = None,
    ) -> None:
        """
        Close an account.

        Rules
        -----
        * If the balance is zero the account is closed immediately.
        * If the balance is non-zero a *sweep_to_account_id* **must** be
          supplied; the remaining funds are transferred before closing.
        * Raises NonZeroBalanceError when balance > 0 and no sweep target
          is provided.
        * Raises AccountAlreadyClosedError if the account is already closed.
        """
        account = self.get_account(account_id)

        if account.is_closed:
            raise AccountAlreadyClosedError(
                f"Account '{account_id}' is already closed."
            )

        if account.balance != Decimal("0"):
            if sweep_to_account_id is None:
                raise NonZeroBalanceError(
                    f"Account '{account_id}' has a non-zero balance "
                    f"({account.balance}). Provide a sweep target account."
                )
            destination = self.get_account(sweep_to_account_id)
            if destination.is_closed:
                raise AccountAlreadyClosedError(
                    f"Sweep target account '{sweep_to_account_id}' is closed."
                )
            swept_amount = account.balance
            account.withdraw(swept_amount)
            destination.deposit(swept_amount)

        account.is_closed = True


